import os
import base64
import zlib
import xml.etree.ElementTree as ET
from flask import Flask, request, session, redirect, url_for, render_template_string, flash

app = Flask(__name__)
app.secret_key = os.urandom(24) # Replace with a strong, permanent key in production

# Define SAML namespaces
SAML_PROTOCOL_NAMESPACE = 'urn:oasis:names:tc:SAML:2.0:protocol'
SAML_ASSERTION_NAMESPACE = 'urn:oasis:names:tc:SAML:2.0:assertion'

NAMESPACES = {
    'samlp': SAML_PROTOCOL_NAMESPACE,
    'saml': SAML_ASSERTION_NAMESPACE
}

# --- Utility Functions ---

def decode_and_inflate(saml_message_b64):
    """
    Decodes a base64 encoded SAML message and inflates it if it's DEFLATE compressed.
    SAML POST binding usually only base64 encodes, but Redirect binding uses DEFLATE.
    This function tries both just in case, but for POST, only base64 decoding is expected.
    """
    decoded = base64.b64decode(saml_message_b64)
    try:
        # Try DEFLATE decompression (common for HTTP-Redirect binding)
        # The -15 is for auto-detecting zlib header (window size)
        decompressed = zlib.decompress(decoded, -15)
        return decompressed.decode('utf-8')
    except zlib.error:
        # If decompression fails, assume it's not compressed (common for HTTP-POST binding)
        return decoded.decode('utf-8')

def extract_saml_attributes(saml_response_xml):
    """
    Parses a SAML XML response, extracts assertions and user attributes.
    """
    try:
        root = ET.fromstring(saml_response_xml)
    except ET.ParseError as e:
        raise ValueError(f"Failed to parse SAML XML: {e}")

    # Check for SAML Response status - simplified, production would check status codes
    # Status = root.find('samlp:Status', NAMESPACES)
    # StatusCode = Status.find('samlp:StatusCode', NAMESPACES)
    # if StatusCode.get('Value') != 'urn:oasis:names:tc:SAML:2.0:status:Success':
    #     raise ValueError("SAML Response status is not Success")

    assertion_element = root.find('.//saml:Assertion', NAMESPACES)
    if assertion_element is None:
        raise ValueError("SAML Assertion element not found in the response.")

    user_data = {}

    # Extract NameID (usually the principal identifier)
    name_id_element = assertion_element.find('.//saml:Subject/saml:NameID', NAMESPACES)
    if name_id_element is not None:
        user_data['name_id'] = name_id_element.text
        user_data['name_id_format'] = name_id_element.get('Format')

    # Extract attributes from AttributeStatement
    attribute_statement = assertion_element.find('.//saml:AttributeStatement', NAMESPACES)
    if attribute_statement is not None:
        for attribute in attribute_statement.findall('saml:Attribute', NAMESPACES):
            name = attribute.get('Name')
            if name:
                # Assuming single AttributeValue per Attribute for simplicity
                value_element = attribute.find('saml:AttributeValue', NAMESPACES)
                if value_element is not None and value_element.text:
                    user_data[name] = value_element.text
                elif value_element is not None: # Handle empty attribute values
                    user_data[name] = ""
    return user_data

